-- Chat messages
WITH cfg AS (
  SELECT ARRAY['좋아요', '여기 어때요?', '지금 출발합니다', '메뉴 추천 부탁해요']::TEXT[] AS short_msgs,
         ARRAY['가게 분위기가 조용해서 대화하기 좋았습니다.', '피크타임에는 웨이팅이 있으니 시간을 조금 앞당기는 걸 추천해요.', '양 대비 가격은 무난했고 재방문 의사 있습니다.']::TEXT[] AS long_msgs
)
INSERT INTO chat_message (chat_room_id, member_id, type, content, created_at)
SELECT
  cr.id,
  m.id,
  'TEXT',
  CASE     WHEN MOD(msg.message_idx, 5) IN (0, 1) THEN '성능 채팅 메시지' || ' #' || (((cr.seq - 1) * 40) + msg.message_idx) || ' ' || cfg.short_msgs[((msg.message_idx - 1) % CARDINALITY(cfg.short_msgs)) + 1]     ELSE '성능 채팅 메시지' || ' #' || (((cr.seq - 1) * 40) + msg.message_idx) || ' ' || cfg.long_msgs[((msg.message_idx - 1) % CARDINALITY(cfg.long_msgs)) + 1]   END,
  NOW()
FROM tmp_dummy_chat_room cr
CROSS JOIN cfg
JOIN tmp_dummy_subgroup sg ON sg.id = cr.subgroup_id
JOIN generate_series(1, 40) AS msg(message_idx) ON TRUE
JOIN tmp_dummy_member m
  ON m.seq = ((((sg.group_seq * 37) % 2000) + ((((sg.group_seq * 31 + sg.subgroup_index * 17) % 20) + ((msg.message_idx - 1) % 20)) % 20)) % 2000) + 1
ORDER BY cr.seq, msg.message_idx;

-- Update last_read_message_id for 70% of chat_room_member rows
UPDATE chat_room_member crm
SET last_read_message_id = latest.max_id
FROM (
  SELECT chat_room_id, MAX(id) AS max_id
  FROM chat_message
  WHERE chat_room_id IN (SELECT id FROM tmp_dummy_chat_room)
  GROUP BY chat_room_id
) AS latest
WHERE crm.chat_room_id = latest.chat_room_id
  AND (crm.id % 10) < 7;

-- Reviews
INSERT INTO tmp_dummy_review (seq, id, member_id, restaurant_id, group_id, subgroup_id, is_recommended)
SELECT
  rv.seq,
  nextval(pg_get_serial_sequence('review', 'id')),
  m.id,
  rest.id,
  g.id,
  sg.id,
  (MOD(rv.seq - 1, 2) = 0)
FROM generate_series(1, 50000) AS rv(seq)
JOIN tmp_dummy_member m
  ON m.seq = (((rv.seq - 1) % 2000) + 1)
JOIN tmp_dummy_group g
  ON g.seq = (((rv.seq - 1) % 200) + 1)
LEFT JOIN tmp_dummy_subgroup sg
  ON sg.group_id = g.id AND sg.subgroup_index = (((rv.seq - 1) % 3) + 1)
JOIN tmp_dummy_restaurant rest
  ON rest.seq = (CASE WHEN MOD(rv.seq - 1, 10) < 6 THEN ((rv.seq - 1) % 120) + 1 ELSE 120 + (((rv.seq - 1) % 1080) + 1) END)
ORDER BY rv.seq;

