  rv.id,
  rv.member_id,
  rv.restaurant_id,
  rv.group_id,
  rv.subgroup_id,
  rv.is_recommended,
  CASE     WHEN MOD(rv.seq, 4) = 0 THEN '성능 테스트 리뷰' || ' ' || cfg.context_lines[((rv.seq - 1) % CARDINALITY(cfg.context_lines)) + 1] || ' ' || cfg.positive_lines[((rv.seq - 1) % CARDINALITY(cfg.positive_lines)) + 1] || ' ' || cfg.negative_lines[((rv.seq - 1) % CARDINALITY(cfg.negative_lines)) + 1]     WHEN MOD(rv.seq, 4) = 1 THEN cfg.context_lines[((rv.seq - 1) % CARDINALITY(cfg.context_lines)) + 1] || ' ' || cfg.positive_lines[((rv.seq - 1) % CARDINALITY(cfg.positive_lines)) + 1]     WHEN MOD(rv.seq, 4) = 2 THEN '성능 테스트 리뷰' || ' ' || cfg.negative_lines[((rv.seq - 1) % CARDINALITY(cfg.negative_lines)) + 1]     ELSE '성능 테스트 리뷰' || ' 방문 ' || rv.seq || '회차 리뷰입니다.'   END,
  NOW(),
  NOW()
FROM tmp_dummy_review rv
CROSS JOIN cfg
ORDER BY rv.seq;

