INSERT INTO member (id, email, nickname, status, role, profile_image_url, introduction, last_login_at, agreed_terms_at, agreed_privacy_at, created_at, updated_at)
SELECT
  nextval('member_seq'),
  tu.identifier || '@test.local',
  tu.nickname,
  'ACTIVE',
  'USER',
  NULL,
  NULL,
  NOW(),
  NOW() - INTERVAL '1 day',
  NOW() - INTERVAL '1 day',
  NOW(),
  NOW()
FROM tmp_loadtest_users tu
ON CONFLICT (email) DO NOTHING;

UPDATE tmp_loadtest_users tu
SET member_id = m.id
FROM member m
WHERE m.email = tu.identifier || '@test.local';

